insert into public.solutions (problem_id, language, file, code, is_primary, sort_order) values
  ('union-find', 'go', 'solution.go', 'package main
import "sort"

type DSU struct {
	parent []int
	rank   []int
}

func newDSU(n int) *DSU {
	p := make([]int, n)
	for i := range p {
		p[i] = i
	}
	return &DSU{parent: p, rank: make([]int, n)}
}

func (d *DSU) find(x int) int {
	for d.parent[x] != x {
		d.parent[x] = d.parent[d.parent[x]] // path compression
		x = d.parent[x]
	}
	return x
}

func (d *DSU) union(a, b int) bool {
	ra, rb := d.find(a), d.find(b)
	if ra == rb {
		return false // same set → would form a cycle
	}
	if d.rank[ra] < d.rank[rb] {
		ra, rb = rb, ra
	}
	d.parent[rb] = ra
	if d.rank[ra] == d.rank[rb] {
		d.rank[ra]++
	}
	return true
}

func kruskal(n int, edges [][3]int) (mst [][3]int, total int) {
	sort.Slice(edges, func(i, j int) bool { return edges[i][2] < edges[j][2] })
	dsu := newDSU(n)
	for _, e := range edges {
		if len(mst) == n-1 {
			break
		}
		if dsu.union(e[0], e[1]) {
			mst = append(mst, e)
			total += e[2]
		}
	}
	return mst, total
}
', true, 0),
  ('tree-traversals', 'go', 'solution.go', 'package main
type Node struct{ Val int; Left, Right *Node }

func inorder(n *Node, out *[]int) {
	if n == nil {
		return
	}
	inorder(n.Left, out)
	*out = append(*out, n.Val)
	inorder(n.Right, out)
}

func levelOrder(root *Node) []int {
	out := []int{}
	if root == nil {
		return out
	}
	q := []*Node{root}
	for len(q) > 0 {
		n := q[0]
		q = q[1:]
		out = append(out, n.Val)
		if n.Left != nil {
			q = append(q, n.Left)
		}
		if n.Right != nil {
			q = append(q, n.Right)
		}
	}
	return out
}
', true, 0),
  ('trie', 'go', 'solution.go', 'package main
type node struct {
	children map[rune]*node
	isEnd    bool
}

func newNode() *node {
	return &node{children: make(map[rune]*node)}
}

type Trie struct{ root *node }

func NewTrie() *Trie { return &Trie{root: newNode()} }

func (t *Trie) Insert(word string) {
	cur := t.root
	for _, ch := range word {
		next, ok := cur.children[ch]
		if !ok {
			next = newNode()
			cur.children[ch] = next
		}
		cur = next
	}
	cur.isEnd = true
}

func (t *Trie) Search(word string) bool {
	cur := t.root
	for _, ch := range word {
		next, ok := cur.children[ch]
		if !ok {
			return false
		}
		cur = next
	}
	return cur.isEnd
}
', true, 0),
  ('binary-search', 'go', 'solution.go', 'package main
func search(nums []int, target int) int {
	lo, hi := 0, len(nums)-1
	for lo <= hi {
		mid := (lo + hi) / 2
		switch {
		case nums[mid] == target:
			return mid
		case nums[mid] < target:
			lo = mid + 1
		default:
			hi = mid - 1
		}
	}
	return -1
}
', true, 0),
  ('binary-search', 'python', 'solution.py', '# Binary Search — LeetCode #704
# Time: O(log n) | Space: O(1)

def search(nums: list[int], target: int) -> int:
    lo, hi = 0, len(nums) - 1
    while lo <= hi:
        mid = (lo + hi) // 2
        if nums[mid] == target:
            return mid
        if nums[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1
