  ('heap-operations', 'go', 'solution.go', 'package main
type MinHeap struct{ a []int }

func (h *MinHeap) Insert(v int) {
	h.a = append(h.a, v)
	h.siftUp(len(h.a) - 1)
}

func (h *MinHeap) ExtractMin() (int, bool) {
	if len(h.a) == 0 {
		return 0, false
	}
	min := h.a[0]
	last := len(h.a) - 1
	h.a[0] = h.a[last]
	h.a = h.a[:last]
	if len(h.a) > 0 {
		h.siftDown(0)
	}
	return min, true
}

func (h *MinHeap) siftUp(i int) {
	for i > 0 {
		p := (i - 1) / 2
		if h.a[i] >= h.a[p] {
			return
		}
		h.a[i], h.a[p] = h.a[p], h.a[i]
		i = p
	}
}

func (h *MinHeap) siftDown(i int) {
	n := len(h.a)
	for {
		l, r, smallest := 2*i+1, 2*i+2, i
		if l < n && h.a[l] < h.a[smallest] {
			smallest = l
		}
		if r < n && h.a[r] < h.a[smallest] {
			smallest = r
		}
		if smallest == i {
			return
		}
		h.a[i], h.a[smallest] = h.a[smallest], h.a[i]
		i = smallest
	}
}
