  ('n-queens', 'go', 'solution.go', 'package main
func solveNQueens(n int) ([]int, bool) {
	queens := make([]int, n)
	for i := range queens {
		queens[i] = -1
	}

	safe := func(row, col int) bool {
		for r := 0; r < row; r++ {
			c := queens[r]
			if c == col || abs(c-col) == abs(r-row) {
				return false
			}
		}
		return true
	}

	var place func(row int) bool
	place = func(row int) bool {
		if row == n {
			return true
		}
		for col := 0; col < n; col++ {
			if safe(row, col) {
				queens[row] = col
				if place(row + 1) {
					return true
				}
				queens[row] = -1 // backtrack
			}
		}
		return false
	}

	if place(0) {
		return queens, true
	}
	return nil, false
}

func abs(x int) int {
	if x < 0 {
		return -x
	}
	return x
}
