func bfs(n int, edges [][]int, start int) []int {
	if start < 1 || start > n {
		res := make([]int, n-1)
		for i := range res {
			res[i] = -1
		}
		return res
	}
	adj := make([][]int, n+1)
	for _, e := range edges {
		adj[e[0]] = append(adj[e[0]], e[1])
		adj[e[1]] = append(adj[e[1]], e[0])
	}
	dist := make([]int, n+1)
	for i := range dist {
		dist[i] = -1
	}
	dist[start] = 0
	q := []int{start}
	for len(q) > 0 {
		cur := q[0]
		q = q[1:]
		for _, nb := range adj[cur] {
			if dist[nb] == -1 {
				dist[nb] = dist[cur] + 6
				q = append(q, nb)
			}
		}
	}
	res := make([]int, 0, n-1)
	for i := 1; i <= n; i++ {
		if i != start {
			res = append(res, dist[i])
		}
	}
	return res
}
