  ('imp-0-02-clone-graph', 'go', 'solution.go', 'package main

type GraphNode struct {
	Label     int
	Neighbors []*GraphNode
}

func cloneGraph(src *GraphNode) *GraphNode {
	if src == nil {
		return nil
	}
	memo := make(map[*GraphNode]*GraphNode)
	return btCloneGraph(src, memo)
}

func btCloneGraph(n *GraphNode, memo map[*GraphNode]*GraphNode) *GraphNode {
	if c, ok := memo[n]; ok {
		return c
	}
	copy := &GraphNode{Label: n.Label}
	memo[n] = copy
	for _, nb := range n.Neighbors {
		copy.Neighbors = append(copy.Neighbors, btCloneGraph(nb, memo))
	}
	return copy
}
