  ('imp-0-07-shortest-distance-from-all-buildings', 'go', 'solution.go', 'package main

func shortestDistance(grid [][]int) int {
	m, n := len(grid), len(grid[0])
	totalDist := make([][]int, m)
	reach := make([][]int, m)
	for i := range totalDist {
		totalDist[i] = make([]int, n)
		reach[i] = make([]int, n)
	}
	buildings := 0
	dirs := [4][2]int{{0, 1}, {0, -1}, {1, 0}, {-1, 0}}
	for r := 0; r < m; r++ {
		for c := 0; c < n; c++ {
			if grid[r][c] == 1 {
				buildings++
				vis := make([][]bool, m)
				for k := range vis {
					vis[k] = make([]bool, n)
				}
				q := [][2]int{{r, c}}
				vis[r][c] = true
				dist := 0
				for len(q) > 0 {
					dist++
					sz := len(q)
					for s := 0; s < sz; s++ {
						cur := q[0]
						q = q[1:]
						for _, d := range dirs {
							nr, nc := cur[0]+d[0], cur[1]+d[1]
							if nr >= 0 && nr < m && nc >= 0 && nc < n && !vis[nr][nc] && grid[nr][nc] == 0 {
								vis[nr][nc] = true
								totalDist[nr][nc] += dist
								reach[nr][nc]++
								q = append(q, [2]int{nr, nc})
							}
						}
					}
				}
			}
		}
	}
	res := 1 << 30
	for r := 0; r < m; r++ {
		for c := 0; c < n; c++ {
			if grid[r][c] == 0 && reach[r][c] == buildings && totalDist[r][c] < res {
				res = totalDist[r][c]
			}
		}
	}
	if res == 1<<30 {
		return -1
	}
	return res
}
