  ('imp-2-alien-dictionary', 'go', 'solution.go', 'package main

func alienOrder(words []string) string {
	adj := map[byte]map[byte]bool{}
	inDeg := map[byte]int{}
	for _, w := range words {
		for i := 0; i < len(w); i++ {
			if adj[w[i]] == nil {
				adj[w[i]] = map[byte]bool{}
			}
			inDeg[w[i]] += 0
		}
	}
	for i := 0; i < len(words)-1; i++ {
		w1, w2 := words[i], words[i+1]
		if len(w1) > len(w2) && w1[:len(w2)] == w2 {
			return ""
		}
		for j := 0; j < len(w1) && j < len(w2); j++ {
			if w1[j] != w2[j] {
				if !adj[w1[j]][w2[j]] {
					adj[w1[j]][w2[j]] = true
					inDeg[w2[j]]++
				}
				break
			}
		}
	}
	var q []byte
	for ch := range inDeg {
		if inDeg[ch] == 0 {
			q = append(q, ch)
		}
	}
	var res []byte
	for len(q) > 0 {
		ch := q[0]
		q = q[1:]
		res = append(res, ch)
		for nb := range adj[ch] {
			inDeg[nb]--
			if inDeg[nb] == 0 {
				q = append(q, nb)
			}
		}
	}
	if len(res) != len(inDeg) {
		return ""
	}
	return string(res)
}
