  ('imp-3-remove-invalid-parentheses', 'go', 'solution.go', 'package main

func removeInvalidParentheses(s string) []string {
	vis := map[string]bool{s: true}
	q := []string{s}
	var res []string
	found := false
	for len(q) > 0 && !found {
		sz := len(q)
		for i := 0; i < sz; i++ {
			cur := q[0]
			q = q[1:]
			if isValid(cur) {
				res = append(res, cur)
				found = true
			}
			if found {
				continue
			}
			for j := 0; j < len(cur); j++ {
				if cur[j] != ''('' && cur[j] != '')'' {
					continue
				}
				next := cur[:j] + cur[j+1:]
				if !vis[next] {
					vis[next] = true
					q = append(q, next)
				}
			}
		}
	}
	return res
}

func isValid(s string) bool {
	cnt := 0
	for i := 0; i < len(s); i++ {
		if s[i] == ''('' {
			cnt++
		} else if s[i] == '')'' {
			cnt--
		}
		if cnt < 0 {
			return false
		}
	}
	return cnt == 0
}
