  ('imp-4-floyd-city-of-blinding-lights', 'go', 'solution.go', 'package main

const INF = 1 << 30

func floydWarshall(n int, edges [][]int, queries [][]int) []int {
	dist := make([][]int, n+1)
	for i := range dist {
		dist[i] = make([]int, n+1)
		for j := range dist[i] {
			dist[i][j] = INF
		}
		dist[i][i] = 0
	}
	for _, e := range edges {
		u, v, w := e[0], e[1], e[2]
		dist[u][v] = w
	}
	for k := 1; k <= n; k++ {
		for i := 1; i <= n; i++ {
			for j := 1; j <= n; j++ {
				if dist[i][k]+dist[k][j] < dist[i][j] {
					dist[i][j] = dist[i][k] + dist[k][j]
				}
			}
		}
	}
	results := make([]int, len(queries))
	for i, q := range queries {
		u, v := q[0], q[1]
		if u < 1 || u > n || v < 1 || v > n {
			results[i] = -1
		} else {
			results[i] = query(dist, u, v)
		}
	}
	return results
}

func query(dist [][]int, u, v int) int {
	if dist[u][v] >= INF {
		return -1
	}
	return dist[u][v]
}
