func isBipartite(adj [][]int) bool {
	color := make([]int, len(adj))
	for i := range adj {
		if color[i] != 0 {
			continue
		}
		q := []int{i}
		color[i] = 1
		for len(q) > 0 {
			v := q[0]
			q = q[1:]
			for _, nb := range adj[v] {
				if color[nb] == 0 {
					color[nb] = 3 - color[v]
					q = append(q, nb)
				} else if color[nb] == color[v] {
					return false
				}
			}
		}
	}
	return true
}
