  ('imp-8-merging-communities', 'go', 'solution.go', 'package main

import (
	"fmt"
	"io"
)

type DSU struct {
	parent, size []int
}

func NewDSU(n int) *DSU {
	parent := make([]int, n+1)
	size := make([]int, n+1)
	for i := range parent {
		parent[i] = i
		size[i] = 1
	}
	return &DSU{parent, size}
}

func (d *DSU) Find(x int) int {
	if d.parent[x] != x {
		d.parent[x] = d.Find(d.parent[x])
	}
	return d.parent[x]
}

func (d *DSU) Union(x, y int) {
	rx, ry := d.Find(x), d.Find(y)
	if rx == ry {
		return
	}
	if d.size[rx] < d.size[ry] {
		rx, ry = ry, rx
	}
	d.parent[ry] = rx
	d.size[rx] += d.size[ry]
}

func (d *DSU) Size(x int) int {
	return d.size[d.Find(x)]
}

func SolveMergingCommunities(r io.Reader, w io.Writer) {
	var n, q int
	if _, err := fmt.Fscan(r, &n, &q); err != nil {
		return
	}
	dsu := NewDSU(n)
	for i := 0; i < q; i++ {
		var op string
		if _, err := fmt.Fscan(r, &op); err != nil {
			return
		}
		if op == "M" {
			var u, v int
			fmt.Fscan(r, &u, &v)
			dsu.Union(u, v)
		} else if op == "Q" {
			var u int
			fmt.Fscan(r, &u)
			fmt.Fprintln(w, dsu.Size(u))
		}
	}
}
