  ('imp-9-similar-string-groups', 'go', 'solution.go', 'package main

func numSimilarGroups(strs []string) int {
	n := len(strs)
	parent := make([]int, n)
	size := make([]int, n)
	for i := range parent {
		parent[i] = i
		size[i] = 1
	}
	groups := n
	for i := 0; i < n; i++ {
		for j := i + 1; j < n; j++ {
			diffs := 0
			for k := 0; k < len(strs[i]); k++ {
				if strs[i][k] != strs[j][k] {
					diffs++
					if diffs > 2 {
						break
					}
				}
			}
			if diffs == 0 || diffs == 2 {
				similarGroupsUnion(parent, size, &groups, i, j)
			}
		}
	}
	return groups
}

func similarGroupsFind(parent []int, x int) int {
	if parent[x] != x {
		parent[x] = similarGroupsFind(parent, parent[x])
	}
	return parent[x]
}

func similarGroupsUnion(parent, size []int, groups *int, x, y int) {
	rx, ry := similarGroupsFind(parent, x), similarGroupsFind(parent, y)
	if rx == ry {
		return
	}
	if size[rx] < size[ry] {
		rx, ry = ry, rx
	}
	parent[ry] = rx
	size[rx] += size[ry]
	*groups--
}
