  ('imp-10-word-ladder', 'go', 'solution.go', 'package main

func ladderLength(beginWord string, endWord string, wordList []string) int {
	wordSet := map[string]bool{}
	for _, w := range wordList {
		wordSet[w] = true
	}
	if !wordSet[endWord] {
		return 0
	}
	q := []string{beginWord}
	steps := 0
	for len(q) > 0 {
		steps++
		sz := len(q)
		for i := 0; i < sz; i++ {
			cur := q[0]
			q = q[1:]
			if cur == endWord {
				return steps
			}
			buf := []byte(cur)
			for j := 0; j < len(buf); j++ {
				orig := buf[j]
				for c := byte(''a''); c <= ''z''; c++ {
					if c == orig {
						continue
					}
					buf[j] = c
					w := string(buf)
					if wordSet[w] {
						q = append(q, w)
						delete(wordSet, w)
					}
				}
				buf[j] = orig
			}
		}
	}
	return 0
}
