type Robot interface {
	Move() bool
	TurnLeft()
	TurnRight()
	Clean()
}

func cleanRoom(robot Robot) {
	dirs := [4][2]int{{-1, 0}, {0, 1}, {1, 0}, {0, -1}}
	vis := map[[2]int]bool{}
	btCleanRoom(robot, dirs, vis, 0, 0, 0)
}

func btCleanRoom(robot Robot, dirs [4][2]int, vis map[[2]int]bool, r, c, d int) {
	vis[[2]int{r, c}] = true
	robot.Clean()
	for i := 0; i < 4; i++ {
		nd := (d + i) % 4
		nr, nc := r+dirs[nd][0], c+dirs[nd][1]
		if !vis[[2]int{nr, nc}] && robot.Move() {
			btCleanRoom(robot, dirs, vis, nr, nc, nd)
			robot.TurnRight()
			robot.TurnRight()
			robot.Move()
			robot.TurnRight()
			robot.TurnRight()
		}
		robot.TurnRight()
	}
}
