import "sort"

type logsByTimestamp struct {
	logs [][]int
}

func (l logsByTimestamp) Len() int { return len(l.logs) }
func (l logsByTimestamp) Less(i, j int) bool {
	return l.logs[i][0] < l.logs[j][0]
}
func (l logsByTimestamp) Swap(i, j int) { l.logs[i], l.logs[j] = l.logs[j], l.logs[i] }

func earliestAcq(logs [][]int, n int) int {
	sort.Sort(logsByTimestamp{logs: logs})
	parent := make([]int, n)
	size := make([]int, n)
	for i := range parent {
		parent[i] = i
		size[i] = 1
	}
	groups := n
	for _, l := range logs {
		earliestAcqUnion(parent, size, &groups, l[1], l[2])
		if groups == 1 {
			return l[0]
		}
	}
	return -1
}

func earliestAcqFind(parent []int, x int) int {
	if parent[x] != x {
		parent[x] = earliestAcqFind(parent, parent[x])
	}
	return parent[x]
}

func earliestAcqUnion(parent, size []int, groups *int, x, y int) {
	rx, ry := earliestAcqFind(parent, x), earliestAcqFind(parent, y)
	if rx == ry {
		return
	}
	if size[rx] < size[ry] {
		rx, ry = ry, rx
	}
	parent[ry] = rx
	size[rx] += size[ry]
	*groups--
}
