func maximumDetonation(bombs [][]int) int {
	n := len(bombs)
	adj := make([][]int, n)
	for i := 0; i < n; i++ {
		for j := 0; j < n; j++ {
			if i == j {
				continue
			}
			dx := int64(bombs[i][0] - bombs[j][0])
			dy := int64(bombs[i][1] - bombs[j][1])
			r := int64(bombs[i][2])
			if dx*dx+dy*dy <= r*r {
				adj[i] = append(adj[i], j)
			}
		}
	}
	res := 0
	for i := 0; i < n; i++ {
		vis := make([]bool, n)
		cnt := btDetonate(adj, vis, i)
		if cnt > res {
			res = cnt
		}
	}
	return res
}

func btDetonate(adj [][]int, vis []bool, u int) int {
	vis[u] = true
	cnt := 1
	for _, v := range adj[u] {
		if !vis[v] {
			cnt += btDetonate(adj, vis, v)
		}
	}
	return cnt
}
