func maximalNetworkRank(n int, roads [][]int) int {
	deg := make([]int, n)
	edges := map[[2]int]bool{}
	for _, r := range roads {
		u, v := r[0], r[1]
		deg[u]++
		deg[v]++
		if u > v {
			u, v = v, u
		}
		edges[[2]int{u, v}] = true
	}
	res := 0
	for i := 0; i < n; i++ {
		for j := i + 1; j < n; j++ {
			rank := deg[i] + deg[j]
			if edges[[2]int{i, j}] {
				rank--
			}
			if rank > res {
				res = rank
			}
		}
	}
	return res
}
