	ids  []int
}

func (b idsByVal) Len() int { return len(b.ids) }
func (b idsByVal) Less(i, j int) bool {
	return b.vals[b.ids[i]] < b.vals[b.ids[j]]
}
func (b idsByVal) Swap(i, j int) { b.ids[i], b.ids[j] = b.ids[j], b.ids[i] }

func numberOfGoodPaths(vals []int, edges [][]int) int {
	n := len(vals)
	parent := make([]int, n)
	for i := range parent {
		parent[i] = i
	}
	adj := make([][]int, n)
	for _, e := range edges {
		adj[e[0]] = append(adj[e[0]], e[1])
		adj[e[1]] = append(adj[e[1]], e[0])
	}
	ids := make([]int, n)
	for i := range ids {
		ids[i] = i
	}
	sort.Sort(idsByVal{vals: vals, ids: ids})
	res := n
	i := 0
	for i < n {
		j := i
		for j < n && vals[ids[j]] == vals[ids[i]] {
			j++
		}
		for k := i; k < j; k++ {
			u := ids[k]
			for _, v := range adj[u] {
				if vals[v] <= vals[u] {
					goodPathsUnion(parent, vals, u, v)
				}
			}
		}
		cnt := map[int]int{}
		for k := i; k < j; k++ {
			cnt[goodPathsFind(parent, ids[k])]++
		}
		for _, c := range cnt {
			res += c * (c - 1) / 2
		}
		i = j
	}
	return res
}

func goodPathsFind(parent []int, x int) int {
	if parent[x] != x {
		parent[x] = goodPathsFind(parent, parent[x])
	}
	return parent[x]
}

func goodPathsUnion(parent, vals []int, x, y int) {
	rx, ry := goodPathsFind(parent, x), goodPathsFind(parent, y)
	if rx != ry {
		if vals[rx] < vals[ry] {
			parent[rx] = ry
		} else {
			parent[ry] = rx
		}
	}
}
