func btStrobo(path []byte, low, high int, res *[]string) {
	if low > high {
		*res = append(*res, string(path))
		return
	}
	if low == high {
		for _, c := range []byte{''0'', ''1'', ''8''} {
			path[low] = c
			*res = append(*res, string(path))
		}
		return
	}
	pairs := [][2]byte{{''0'', ''0''}, {''1'', ''1''}, {''8'', ''8''}, {''6'', ''9''}, {''9'', ''6''}}
	for _, pair := range pairs {
		if low == 0 && pair[0] == ''0'' {
			continue
		}
		path[low] = pair[0]
		path[high] = pair[1]
		btStrobo(path, low+1, high-1, res)
	}
}
