func maxLength(arr []string) int {
	var masks []uint
	for _, s := range arr {
		mask := uint(0)
		dup := false
		for i := 0; i < len(s); i++ {
			bit := uint(1) << (s[i] - ''a'')
			if mask&bit > 0 {
				dup = true
				break
			}
			mask |= bit
		}
		if !dup {
