func btIP(s string, idx, dots int, path string, res *[]string) {
	if dots == 3 {
		if btValidIPPart(s[idx:]) {
			*res = append(*res, path+"."+s[idx:])
		}
		return
	}
	for i := idx; i < len(s); i++ {
		if i > idx && s[idx] == ''0'' {
			break
		}
		part := s[idx : i+1]
		if !btValidIPPart(part) {
			continue
		}
		sep := "."
		if path == "" {
			sep = ""
		}
		btIP(s, i+1, dots+1, path+sep+part, res)
	}
}

func btValidIPPart(part string) bool {
	if len(part) == 0 || len(part) > 3 {
		return false
	}
	if len(part) > 1 && part[0] == ''0'' {
		return false
	}
	val := 0
	for i := 0; i < len(part); i++ {
		val = val*10 + int(part[i]-''0'')
	}
	return val <= 255
}
