func coinChangeMemo(coins []int, amount int) int {
	const inf = 1 << 30
	memo := map[int]int{}
	ans := btCoinChange(amount, coins, inf, memo)
	if ans == inf {
		return -1
	}
	return ans
}

func btCoinChange(a int, coins []int, inf int, memo map[int]int) int {
	if a == 0 {
		return 0
	}
	if v, ok := memo[a]; ok {
		return v
	}
	best := inf
	for _, c := range coins {
		if c <= a {
			sub := btCoinChange(a-c, coins, inf, memo)
			if sub != inf && sub+1 < best {
				best = sub + 1
			}
		}
	}
	memo[a] = best
	return best
}
