func btKnapsack(weights, values []int, idx, cap int, memo map[[2]int]int) int {
	if idx == len(weights) || cap == 0 {
		return 0
	}
	key := [2]int{idx, cap}
	if v, ok := memo[key]; ok {
		return v
	}
	best := btKnapsack(weights, values, idx+1, cap, memo)
	w, val := weights[idx], values[idx]
	if w <= cap {
		best = max(best, val+btKnapsack(weights, values, idx+1, cap-w, memo))
	}
	memo[key] = best
	return best
}
