func maxRectangleSumInMatrix(matrix [][]byte) int {
	if len(matrix) == 0 {
		return 0
	}
	m, n := len(matrix), len(matrix[0])
	heights := make([]int, n)
	res := 0
	for r := 0; r < m; r++ {
		for c := 0; c < n; c++ {
			if matrix[r][c] == ''1'' {
				heights[c]++
			} else {
				heights[c] = 0
			}
		}
		res = max(res, btMaxRectHistogram(heights))
	}
