  ('imp-79-partition-array-into-two-arrays-to-minimize-sum-', 'go', 'solution.go', 'package main

import "sort"

func absInt(x int) int {
	if x < 0 {
		return -x
	}
	return x
}

func minimumDifference(nums []int) int {
	n := len(nums) / 2
	total := 0
	for _, x := range nums {
		total += x
	}
	left, right := nums[:n], nums[n:]
	ls, rs := genSubsetSums(left), genSubsetSums(right)
	for i := range rs {
		sort.Ints(rs[i])
	}
	res := 1 << 30
	target := total / 2
	for sz := 0; sz <= n; sz++ {
		rSz := n - sz
		for _, lSum := range ls[sz] {
			t := target - lSum
			arr := rs[rSz]
			idx := sort.Search(len(arr), func(i int) bool { return arr[i] >= t })
			if idx < len(arr) {
				d := absInt(total - 2*(lSum+arr[idx]))
				if d < res {
					res = d
				}
			}
			if idx > 0 {
				d := absInt(total - 2*(lSum+arr[idx-1]))
				if d < res {
					res = d
				}
			}
		}
	}
	return res
}

func genSubsetSums(arr []int) [][]int {
	k := len(arr)
	sums := make([][]int, k+1)
	for mask := 0; mask < (1 << k); mask++ {
		s, cnt := 0, 0
		for i := 0; i < k; i++ {
			if mask&(1<<i) != 0 {
				s += arr[i]
				cnt++
			}
		}
		sums[cnt] = append(sums[cnt], s)
	}
	return sums
}
