func isMatch(s string, p string) bool {
	memo := make([][]int, len(s)+1)
	for i := range memo {
		memo[i] = make([]int, len(p)+1)
		for j := range memo[i] {
			memo[i][j] = -1
		}
	}
	return btIsMatch(s, p, 0, 0, memo)
}

func btIsMatch(s, p string, i, j int, memo [][]int) bool {
	if memo[i][j] != -1 {
		return memo[i][j] == 1
	}
	var res bool
	if i == len(s) && j == len(p) {
		res = true
	} else if j == len(p) {
		res = false
	} else {
		match := i < len(s) && (s[i] == p[j] || p[j] == ''.'')
		if j+1 < len(p) && p[j+1] == ''*'' {
			res = btIsMatch(s, p, i, j+2, memo) || (match && btIsMatch(s, p, i+1, j, memo))
		} else {
			res = match && btIsMatch(s, p, i+1, j+1, memo)
		}
	}
	if res {
		memo[i][j] = 1
	} else {
		memo[i][j] = 0
	}
	return res
}
