		nd[0][0] = (dp[0][0] + dp[0][1] + dp[0][2]) % mod
		nd[1][0] = (dp[1][0] + dp[1][1] + dp[1][2]) % mod
		nd[0][1] = dp[0][0]
		nd[0][2] = dp[0][1]
		nd[1][1] = dp[1][0]
		nd[1][2] = dp[1][1]
		nd[1][0] = (nd[1][0] + dp[0][0] + dp[0][1] + dp[0][2]) % mod
		dp = nd
	}
	res := 0
	for a := 0; a < 2; a++ {
		for l := 0; l < 3; l++ {
