func isValidPalindrome(s string, k int) bool {
	n := len(s)
	dp := make([]int, n)
	for i := range dp {
		dp[i] = 1
	}
	for i := n - 2; i >= 0; i-- {
		prev := 0
		for j := i + 1; j < n; j++ {
			tmp := dp[j]
			if s[i] == s[j] {
				dp[j] = prev + 2
			} else if dp[j-1] > dp[j] {
				dp[j] = dp[j-1]
			}
			prev = tmp
		}
	}
	return n-dp[n-1] <= k
}
