func maxProductOfSubarray(nums []int) int {
	best := nums[0]
	curMax, curMin := nums[0], nums[0]
	for i := 1; i < len(nums); i++ {
		v := nums[i]
		if v < 0 {
			curMax, curMin = curMin, curMax
		}
		hi, lo := curMax*v, curMin*v
		curMax = max(v, hi, lo)
		curMin = min(v, hi, lo)
		if curMax > best {
			best = curMax
		}
	}
	return best
}
