  ('prep-design-dictionary-and-spell', 'go', 'solution.go', 'package main
type dictNode struct {
	children map[rune]*dictNode
	word     bool
}

type dictionaryAndSpell struct {
	root *dictNode
}

func newDictionaryAndSpell(words []string) *dictionaryAndSpell {
	d := &dictionaryAndSpell{root: &dictNode{children: map[rune]*dictNode{}}}
	for _, w := range words {
		d.addWord(w)
	}
	return d
}

func (d *dictionaryAndSpell) addWord(word string) {
	node := d.root
	for _, ch := range word {
		if node.children[ch] == nil {
			node.children[ch] = &dictNode{children: map[rune]*dictNode{}}
		}
		node = node.children[ch]
	}
	node.word = true
}

func (d *dictionaryAndSpell) search(word string) bool {
	node := d.root
	for _, ch := range word {
		if node.children[ch] == nil {
			return false
		}
		node = node.children[ch]
	}
	return node.word
}

func (d *dictionaryAndSpell) suggest(prefix string, limit int) []string {
	node := d.root
	for _, ch := range prefix {
		if node.children[ch] == nil {
			return nil
		}
		node = node.children[ch]
	}
	var out []string
	var dfs func(n *dictNode, path string)
	dfs = func(n *dictNode, path string) {
		if len(out) >= limit {
			return
		}
		if n.word {
			out = append(out, path)
		}
		for ch, child := range n.children {
			dfs(child, path+string(ch))
		}
	}
	dfs(node, prefix)
	return out
}
