  ('prep-design-find-servers-that-handled-most-number-of-requests', 'go', 'solution.go', 'package main
import (
	"container/heap"
	"sort"
)


type srvItem struct{ freeTime, id int }
type srvHeap []srvItem

func (h srvHeap) Len() int            { return len(h) }
func (h srvHeap) Less(i, j int) bool  { return h[i].freeTime < h[j].freeTime }
func (h srvHeap) Swap(i, j int)       { h[i], h[j] = h[j], h[i] }
func (h *srvHeap) Push(x interface{}) { *h = append(*h, x.(srvItem)) }
func (h *srvHeap) Pop() interface{}   { old := *h; x := old[len(old)-1]; *h = old[:len(old)-1]; return x }

func busiestServers(k int, arrival []int, load []int) []int {
	busy := &srvHeap{}
	avail := make([]int, k)
	for i := range avail {
		avail[i] = i
	}
	cnt := make([]int, k)
	for i, arr := range arrival {
		for busy.Len() > 0 && (*busy)[0].freeTime <= arr {
			s := heap.Pop(busy).(srvItem)
			idx := sort.SearchInts(avail, s.id)
			avail = append(avail[:idx], append([]int{s.id}, avail[idx:]...)...)
		}
		if len(avail) == 0 {
			continue
		}
		target := i % k
		idx := sort.SearchInts(avail, target)
		if idx == len(avail) {
			idx = 0
		}
		srv := avail[idx]
		avail = append(avail[:idx], avail[idx+1:]...)
		cnt[srv]++
		heap.Push(busy, srvItem{arr + load[i], srv})
	}
	mx := 0
	for _, c := range cnt {
		if c > mx {
			mx = c
		}
	}
	var res []int
	for i, c := range cnt {
		if c == mx {
			res = append(res, i)
		}
	}
	return res
}
