type RandomizedSet struct {
	nums []int
	idx  map[int]int
}

func Constructor() RandomizedSet { return RandomizedSet{idx: map[int]int{}} }

func (s *RandomizedSet) Insert(val int) bool {
	if _, ok := s.idx[val]; ok {
		return false
	}
	s.idx[val] = len(s.nums)
	s.nums = append(s.nums, val)
	return true
}

func (s *RandomizedSet) Remove(val int) bool {
	i, ok := s.idx[val]
	if !ok {
		return false
	}
	last := s.nums[len(s.nums)-1]
	s.nums[i] = last
	s.idx[last] = i
	s.nums = s.nums[:len(s.nums)-1]
	delete(s.idx, val)
	return true
}

func (s *RandomizedSet) GetRandom() int { return s.nums[rand.Intn(len(s.nums))] }
