  ('prep-design-lru-cache', 'go', 'solution.go', 'package main
type node struct {
	key, val   int
	prev, next *node
}

type LRUCache struct {
	cap        int
	cache      map[int]*node
	head, tail *node
}

func Constructor(capacity int) LRUCache {
	h, t := &node{}, &node{}
	h.next, t.prev = t, h
	return LRUCache{cap: capacity, cache: map[int]*node{}, head: h, tail: t}
}

func (c *LRUCache) remove(n *node) { n.prev.next, n.next.prev = n.next, n.prev }
func (c *LRUCache) addHead(n *node) {
	n.next, n.prev = c.head.next, c.head
	c.head.next.prev, c.head.next = n, n
}
func (c *LRUCache) moveHead(n *node) { c.remove(n); c.addHead(n) }

func (c *LRUCache) Get(key int) int {
	if n, ok := c.cache[key]; ok {
		c.moveHead(n)
		return n.val
	}
	return -1
}

func (c *LRUCache) Put(key, value int) {
	if n, ok := c.cache[key]; ok {
		n.val = value
		c.moveHead(n)
		return
	}
	if len(c.cache) >= c.cap {
		lru := c.tail.prev
		c.remove(lru)
		delete(c.cache, lru.key)
	}
	n := &node{key: key, val: value}
	c.cache[key] = n
	c.addHead(n)
}
