type phoneNode struct {
	children map[byte]*phoneNode
	names    []string
}

type phoneDirectory struct {
	root     *phoneNode
	contacts map[string]string
}

func newPhoneDirectory() *phoneDirectory {
	return &phoneDirectory{
		root:     &phoneNode{children: map[byte]*phoneNode{}},
		contacts: map[string]string{},
	}
}

func (pd *phoneDirectory) addContact(number string, name string) {
	pd.contacts[number] = name
	node := pd.root
	for i := 0; i < len(number); i++ {
		ch := number[i]
		if node.children[ch] == nil {
			node.children[ch] = &phoneNode{children: map[byte]*phoneNode{}}
		}
		node = node.children[ch]
		node.names = append(node.names, name)
	}
}

func (pd *phoneDirectory) lookup(number string) (string, bool) {
	name, ok := pd.contacts[number]
	return name, ok
}

func (pd *phoneDirectory) suggest(prefix string) []string {
	node := pd.root
	for i := 0; i < len(prefix); i++ {
		ch := prefix[i]
		if node.children[ch] == nil {
			return nil
		}
		node = node.children[ch]
	}
	return append([]string(nil), node.names...)
}
