  ('prep-design-range-module', 'go', 'solution.go', 'package main
import "sort"


type RangeModule struct{ intervals [][2]int }

func Constructor() RangeModule { return RangeModule{} }

func (rm *RangeModule) AddRange(left, right int) {
	var merged [][2]int
	i, n := 0, len(rm.intervals)
	for i < n && rm.intervals[i][1] < left {
		merged = append(merged, rm.intervals[i])
		i++
	}
	for i < n && rm.intervals[i][0] <= right {
		if rm.intervals[i][0] < left {
			left = rm.intervals[i][0]
		}
		if rm.intervals[i][1] > right {
			right = rm.intervals[i][1]
		}
		i++
	}
	merged = append(merged, [2]int{left, right})
	for i < n {
		merged = append(merged, rm.intervals[i])
		i++
	}
	rm.intervals = merged
}

func (rm *RangeModule) QueryRange(left, right int) bool {
	i := sort.Search(len(rm.intervals), func(i int) bool { return rm.intervals[i][1] > left })
	return i < len(rm.intervals) && rm.intervals[i][0] <= left && rm.intervals[i][1] >= right
}

func (rm *RangeModule) RemoveRange(left, right int) {
	var result [][2]int
	for _, iv := range rm.intervals {
		if iv[1] <= left || iv[0] >= right {
			result = append(result, iv)
		} else {
			if iv[0] < left {
				result = append(result, [2]int{iv[0], left})
			}
			if iv[1] > right {
				result = append(result, [2]int{right, iv[1]})
			}
		}
	}
	rm.intervals = result
}
