func distSq(p [2]int) int { return p[0]*p[0] + p[1]*p[1] }

func findKClosestToCenter(pairs [][2]int, k int) [][2]int {
	cp := append([][2]int(nil), pairs...)
	sort.Slice(cp, func(i, j int) bool {
		return distSq(cp[i]) < distSq(cp[j])
	})
	if k > len(cp) {
		k = len(cp)
	}
	return cp[:k]
}
