  ('prep-hash-maps-find-kth-largest', 'go', 'solution.go', 'package main
func partitionKth(a []int, lo, hi int) int {
	pivot := a[hi]
	store := lo
	for i := lo; i < hi; i++ {
		if a[i] <= pivot {
			a[i], a[store] = a[store], a[i]
			store++
		}
	}
	a[store], a[hi] = a[hi], a[store]
	return store
}

func findKthLargest(a []int, k int) int {
	target := len(a) - k
	lo, hi := 0, len(a)-1
	for lo < hi {
		p := partitionKth(a, lo, hi)
		if p == target {
			return a[p]
		}
		if p < target {
			lo = p + 1
		} else {
			hi = p - 1
		}
	}
	return a[lo]
}
