func findTopKFrequentElements(a []int, k int) []int {
	freq := make(map[int]int)
	for _, x := range a {
		freq[x]++
	}
	buckets := make([][]int, len(a)+1)
	for num, cnt := range freq {
		buckets[cnt] = append(buckets[cnt], num)
	}
	var res []int
	for i := len(buckets) - 1; i >= 0 && len(res) < k; i-- {
		for _, num := range buckets[i] {
			res = append(res, num)
			if len(res) == k {
				break
			}
		}
	}
	return res
}
