  ('prep-hash-maps-find-x-to-make-array-sum-to-k', 'go', 'solution.go', 'package main
import (
	"sort"
)


func cappedSum(a []int, x int) int {
	s := 0
	for _, v := range a {
		if v > x {
			s += x
		} else {
			s += v
		}
	}
	return s
}

func findXToMakeArraySumToK(a []int, target int) int {
	sort.Ints(a)
	lo, hi := a[0], a[len(a)-1]
	for cappedSum(a, hi) < target {
		hi *= 2
	}
	for lo < hi {
		mid := lo + (hi-lo)/2
		if cappedSum(a, mid) >= target {
			hi = mid
		} else {
			lo = mid + 1
		}
	}
	return lo
}
