	for _, y := range years {
		birth, death := y[0], y[1]
		delta[birth]++
		delta[death+1]--
	}
	yearKeys := make([]int, 0, len(delta))
	for yr := range delta {
		yearKeys = append(yearKeys, yr)
	}
	sort.Ints(yearKeys)
	pop, bestPop, bestYear := 0, 0, 0
	for _, yr := range yearKeys {
		pop += delta[yr]
		if pop > bestPop {
			bestPop = pop
			bestYear = yr
		}
	}
	return bestYear
}
