func sortPairs(inputMap map[string]string) []string {
	dest := make(map[string]bool, len(inputMap))
	for _, v := range inputMap {
		dest[v] = true
	}
	var start string
	for k := range inputMap {
		if !dest[k] {
			start = k
			break
		}
	}
	var route []string
	cur := start
	for {
		next, ok := inputMap[cur]
		route = append(route, cur+"-"+next)
		if !ok {
			break
		}
		cur = next
	}
	return route
}
