	Y    float64
	Dist float64
}

func distED(p1, p2 GeoPoint) float64 {
	dx := p1.X - p2.X
	dy := p1.Y - p2.Y
	return dx*dx + dy*dy
}

func distanceOfNearestStores(stores, customers []GeoPoint) []float64 {
	res := make([]float64, len(customers))
	for i, cust := range customers {
		best := -1.0
		for _, store := range stores {
			d := distED(cust, store)
			if best < 0 || d < best {
				best = d
			}
		}
		res[i] = best
	}
	return res
}
