  ('prep-intervals-draw-skyline', 'go', 'solution.go', 'package main
import (
	"sort"
)


type Point struct {
	X, Y int
}

type SkyPoint struct {
	X      int
	Height int
}

func drawSkyline(buildings [][]int) []SkyPoint {
	events := make([]SkyPoint, 0, len(buildings)*2)
	for _, b := range buildings {
		events = append(events, SkyPoint{X: b[0], Height: -b[2]})
		events = append(events, SkyPoint{X: b[1], Height: b[2]})
	}
	sort.Slice(events, func(i, j int) bool {
		if events[i].X != events[j].X {
			return events[i].X < events[j].X
		}
		return events[i].Height < events[j].Height
	})
	heights := map[int]int{0: 1}
	currMax := 0
	res := make([]SkyPoint, 0)
	for _, ev := range events {
		if ev.Height < 0 {
			heights[-ev.Height]++
		} else {
			heights[ev.Height]--
			if heights[ev.Height] == 0 {
				delete(heights, ev.Height)
			}
		}
		newMax := 0
		for h := range heights {
			if h > newMax {
				newMax = h
			}
		}
		if newMax != currMax {
			res = append(res, SkyPoint{X: ev.X, Height: newMax})
			currMax = newMax
		}
	}
	return res
}
