	for i < len(ins) && ins[i].Start <= x.End {
		if ins[i].Start < x.Start {
			x.Start = ins[i].Start
		}
		if ins[i].End > x.End {
			x.End = ins[i].End
		}
		i++
	}
	res = append(res, x)
	for i < len(ins) {
		res = append(res, ins[i])
		i++
	}
	return res
}
