  ('prep-intervals-weighted-job-scheduler', 'go', 'solution.go', 'package main
import (
	"sort"
)


type Job struct {
	Start  int
	End    int
	Profit int
}

func lastNotOverlapJob(jobs []Job, idx int) int {
	lo, hi := 0, idx-1
	res := -1
	for lo <= hi {
		mid := lo + (hi-lo)/2
		if jobs[mid].End <= jobs[idx].Start {
			res = mid
			lo = mid + 1
		} else {
			hi = mid - 1
		}
	}
	return res
}

func maxProfit(jobs []Job) int {
	if len(jobs) == 0 {
		return 0
	}
	sorted := make([]Job, len(jobs))
	copy(sorted, jobs)
	sort.Slice(sorted, func(i, j int) bool {
		return sorted[i].End < sorted[j].End
	})
	n := len(sorted)
	dp := make([]int, n)
	dp[0] = sorted[0].Profit
	for i := 1; i < n; i++ {
		profit := sorted[i].Profit
		prev := lastNotOverlapJob(sorted, i)
		if prev != -1 {
			profit += dp[prev]
		}
		if dp[i-1] > profit {
			dp[i] = dp[i-1]
		} else {
			dp[i] = profit
		}
	}
	return dp[n-1]
}
