type Node struct {
	Val    int
	Next   *Node
	Random *Node
}

func copyRandomList(head *Node) *Node {
	if head == nil {
		return nil
	}
	cur := head
	for cur != nil {
		clone := &Node{Val: cur.Val, Next: cur.Next}
		cur.Next = clone
		cur = clone.Next
	}
	cur = head
	for cur != nil {
		if cur.Random != nil {
			cur.Next.Random = cur.Random.Next
		}
		cur = cur.Next.Next
	}
	dummy := &Node{}
	tail := dummy
	cur = head
	for cur != nil {
		tail.Next = cur.Next
		tail = tail.Next
		cur.Next = cur.Next.Next
		cur = cur.Next
	}
	return dummy.Next
}
