  ('prep-linked-lists-delete-every-kth-node-in-dll', 'go', 'solution.go', 'package main
type DLLNode struct {
	Val        int
	Prev, Next *DLLNode
}

func deleteEveryKthNodeInDll(head *DLLNode, k int) *DLLNode {
	if head == nil || k <= 0 {
		return head
	}
	count := 0
	cur := head
	for cur != nil {
		count++
		cur = cur.Next
	}
	if k > count {
		return head
	}
	cur = head
	step := 0
	for cur != nil {
		step++
		if step == k {
			prev, next := cur.Prev, cur.Next
			if prev != nil {
				prev.Next = next
			} else {
				head = next
			}
			if next != nil {
				next.Prev = prev
			}
			step = 0
			cur = next
			continue
		}
		cur = cur.Next
	}
	return head
}
