  ('prep-linked-lists-flatten-doubly-linked-list', 'go', 'solution.go', 'package main
type MultilevelNode struct {
	Val        int
	Prev, Next *MultilevelNode
	Child      *MultilevelNode
}

func flattenDoublyLinkedList(head *MultilevelNode) *MultilevelNode {
	if head == nil {
		return nil
	}
	var prev *MultilevelNode
	var dfs func(node *MultilevelNode) *MultilevelNode
	dfs = func(node *MultilevelNode) *MultilevelNode {
		if node == nil {
			return nil
		}
		if prev != nil {
			prev.Next = node
			node.Prev = prev
		}
		prev = node
		next := node.Next
		if node.Child != nil {
			tail := dfs(node.Child)
			node.Next = node.Child
			node.Child.Prev = node
			node.Child = nil
			if next != nil {
				tail.Next = next
				next.Prev = tail
			}
			prev = tail
		}
		if next != nil {
			return dfs(next)
		}
		return node
	}
	dfs(head)
	return head
}
