func maxNumberOfFamilies(n int, reservedSeats [][]int) int {
	rows := map[int]int{}
	for _, r := range reservedSeats {
		rows[r[0]] |= 1 << r[1]
	}
	res := 2 * n
	for _, mask := range rows {
		left := mask&0b0000111100 == 0
		mid := mask&0b0011110000 == 0
		right := mask&0b1111000000 == 0
		if left && right {
		} else if left || mid || right {
			res--
		} else {
			res -= 2
		}
	}
	return res
}
