func convertDecimalToBaseN(n int, base int) string {
	if n == 0 {
		return "0"
	}
	const digits = "0123456789ABCDEF"
	neg := n < 0
	if neg {
		n = -n
	}
	var out []byte
	for n > 0 {
		out = append(out, digits[n%base])
		n /= base
	}
	if neg {
		out = append(out, ''-'')
	}
	for l, r := 0, len(out)-1; l < r; l, r = l+1, r-1 {
		out[l], out[r] = out[r], out[l]
	}
	return string(out)
