  ('prep-math-minimum-cost-to-set-cooking-time', 'go', 'solution.go', 'package main
func minCostSetTime(startAt int, moveCost int, pushCost int, targetSeconds int) int {
	costOf := func(m, s int) int {
		if m < 0 || m > 99 || s < 0 || s > 99 {
			return 1 << 30
		}
		var digits []int
		if m >= 10 {
			digits = append(digits, m/10)
		}
		if m > 0 {
			digits = append(digits, m%10)
		}
		if len(digits) > 0 || s >= 10 {
			digits = append(digits, s/10)
		}
		digits = append(digits, s%10)
		cost, pos := 0, startAt
		for _, d := range digits {
			if d != pos {
				cost += moveCost
				pos = d
			}
			cost += pushCost
		}
		return cost
	}
	m, s := targetSeconds/60, targetSeconds%60
	c1 := costOf(m, s)
	c2 := costOf(m-1, s+60)
	if c1 < c2 {
		return c1
	}
	return c2
}
