	m, n := len(num1), len(num2)
	result := make([]int, m+n)
	for i := m - 1; i >= 0; i-- {
		for j := n - 1; j >= 0; j-- {
			mul := int(num1[i]-''0'') * int(num2[j]-''0'')
			sum := mul + result[i+j+1]
			result[i+j+1] = sum % 10
			result[i+j] += sum / 10
		}
	}
	start := 0
	for start < len(result)-1 && result[start] == 0 {
		start++
	}
	var out strings.Builder
	for ; start < len(result); start++ {
		out.WriteByte(byte(''0'' + result[start]))
	}
	return out.String()
}
