	for i := m - 1; i >= 0; i-- {
		for j := n - 1; j >= 0; j-- {
			mul := int(num1[i]-''0'') * int(num2[j]-''0'')
			sum := mul + pos[i+j+1]
			pos[i+j+1] = sum % 10
			pos[i+j] += sum / 10
		}
	}
	var res []byte
	for _, p := range pos {
		if len(res) > 0 || p != 0 {
			res = append(res, byte(''0''+p))
		}
	}
	return string(res)
}
