import (
	"math/rand"
)


func randomNumberNotInArray(maxVal int, blocked []int, seed int64) int {
	blockedSet := make(map[int]bool, len(blocked))
	for _, v := range blocked {
		blockedSet[v] = true
	}
	available := maxVal + 1 - len(blockedSet)
	if available <= 0 {
		return -1
	}
	rng := rand.New(rand.NewSource(seed))
	k := rng.Intn(available)
	for v := 0; v <= maxVal; v++ {
		if blockedSet[v] {
			continue
		}
		if k == 0 {
			return v
		}
		k--
	}
	return -1
}
