func placeWordInCrossword(board [][]byte, word string) bool {
	m, n, wLen := len(board), len(board[0]), len(word)
	matches := func(seg []byte) bool {
		if len(seg) != wLen {
			return false
		}
		fwd, bwd := true, true
		for i := 0; i < wLen; i++ {
			if seg[i] != '' '' && seg[i] != word[i] {
				fwd = false
			}
			if seg[i] != '' '' && seg[i] != word[wLen-1-i] {
				bwd = false
			}
		}
		return fwd || bwd
	}
	for i := 0; i < m; i++ {
		var seg []byte
		for j := 0; j <= n; j++ {
			if j < n && board[i][j] != ''#'' {
				seg = append(seg, board[i][j])
			} else {
				if matches(seg) {
					return true
				}
				seg = nil
			}
		}
	}
	for j := 0; j < n; j++ {
		var seg []byte
		for i := 0; i <= m; i++ {
			if i < m && board[i][j] != ''#'' {
				seg = append(seg, board[i][j])
			} else {
				if matches(seg) {
					return true
				}
				seg = nil
			}
		}
	}
	return false
}
