func fillRowsAndColumnsWith1s(mat [][]int) {
	if len(mat) == 0 {
		return
	}
	m, n := len(mat), len(mat[0])
	row0, col0 := false, false
	for j := 0; j < n; j++ {
		if mat[0][j] == 1 {
