				mat[0][j] = 1
			}
		}
	}
	for i := 1; i < m; i++ {
		for j := 1; j < n; j++ {
			if mat[i][0] == 1 || mat[0][j] == 1 {
				mat[i][j] = 1
			}
		}
	}
	if row0 {
		for j := 0; j < n; j++ {
			mat[0][j] = 1
		}
	}
	if col0 {
