func longestIncreasingPath(mat [][]int) int {
	m, n := len(mat), len(mat[0])
	memo := make([][]int, m)
	for i := range memo {
		memo[i] = make([]int, n)
	}
	dirs := [4][2]int{{0, 1}, {1, 0}, {0, -1}, {-1, 0}}
	var dfs func(int, int) int
	dfs = func(i, j int) int {
		if memo[i][j] != 0 {
			return memo[i][j]
		}
		best := 1
		for _, d := range dirs {
			ni, nj := i+d[0], j+d[1]
			if ni >= 0 && nj >= 0 && ni < m && nj < n && mat[ni][nj] > mat[i][j] {
				if v := dfs(ni, nj) + 1; v > best {
					best = v
				}
			}
		}
		memo[i][j] = best
		return best
	}
	ans := 0
	for i := 0; i < m; i++ {
		for j := 0; j < n; j++ {
			if v := dfs(i, j); v > ans {
				ans = v
			}
		}
	}
	return ans
}
