func longestLine(mat [][]int) int {
	m, n := len(mat), len(mat[0])
	dp := make([][4]int, n)
	res := 0
	for i := 0; i < m; i++ {
		nd := make([][4]int, n)
		for j := 0; j < n; j++ {
			if mat[i][j] == 1 {
				nd[j][0] = 1
				if j > 0 {
					nd[j][0] = nd[j-1][0] + 1
				}
				nd[j][1] = dp[j][1] + 1
				nd[j][2] = 1
				if j > 0 {
					nd[j][2] = dp[j-1][2] + 1
				}
				nd[j][3] = 1
				if j < n-1 {
					nd[j][3] = dp[j+1][3] + 1
				}
				for d := 0; d < 4; d++ {
					if nd[j][d] > res {
						res = nd[j][d]
					}
				}
			}
		}
		dp = nd
	}
	return res
}
