  ('prep-matrices-nearest-bikes', 'go', 'solution.go', 'package main
type Position struct {
	R, C int
}

func absInt(x int) int {
	if x < 0 {
		return -x
	}
	return x
}

func manhattan(a, b Position) int {
	return absInt(a.R-b.R) + absInt(a.C-b.C)
}

func nearestBikes(grid [][]byte) int {
	m, n := len(grid), len(grid[0])
	var bikes, workers []Position
	for r := 0; r < m; r++ {
		for c := 0; c < n; c++ {
			switch grid[r][c] {
			case ''X'':
				bikes = append(bikes, Position{r, c})
			case ''Y'':
				workers = append(workers, Position{r, c})
			}
		}
	}
	best := int(^uint(0) >> 1)
	for _, w := range workers {
		for _, b := range bikes {
			if d := manhattan(w, b); d < best {
				best = d
			}
		}
	}
	return best
}
