func printMatrixInSpiralOrder(mat [][]int) []int {
	if len(mat) == 0 {
		return nil
	}
	startR, startC := 0, 0
	endR, endC := len(mat)-1, len(mat[0])-1
	var res []int
	for startR <= endR && startC <= endC {
		for c := startC; c <= endC; c++ {
			res = append(res, mat[startR][c])
		}
		startR++
		for r := startR; r <= endR; r++ {
			res = append(res, mat[r][endC])
		}
		endC--
		if startR <= endR {
			for c := endC; c >= startC; c-- {
				res = append(res, mat[endR][c])
			}
			endR--
		}
		if startC <= endC {
			for r := endR; r >= startR; r-- {
				res = append(res, mat[r][startC])
			}
			startC++
		}
	}
	return res
}
