func spiralOrder(matrix [][]int) []int {
	var res []int
	top, bot, left, right := 0, len(matrix)-1, 0, len(matrix[0])-1
	for top <= bot && left <= right {
		for c := left; c <= right; c++ {
			res = append(res, matrix[top][c])
		}
		top++
		for r := top; r <= bot; r++ {
			res = append(res, matrix[r][right])
		}
		right--
		if top <= bot {
			for c := right; c >= left; c-- {
				res = append(res, matrix[bot][c])
			}
			bot--
		}
		if left <= right {
			for r := bot; r >= top; r-- {
				res = append(res, matrix[r][left])
			}
			left++
		}
	}
	return res
}
