func arrayManipulation(n int32, queries [][]int32) int64 {
	diff := make([]int64, n+2)
	for _, q := range queries {
		a, b, k := q[0], q[1], int64(q[2])
		diff[a] += k
		diff[b+1] -= k
	}
	var res, cur int64
	for i := int32(1); i <= n; i++ {
		cur += diff[i]
		if cur > res {
			res = cur
		}
	}
	return res
