  ('prep-sorting-equal-sum-arrays-with-minimum-number-of-operations', 'go', 'solution.go', 'package main
func minOperations(nums1 []int, nums2 []int) int {
	if len(nums1) > len(nums2)*6 || len(nums2) > len(nums1)*6 {
		return -1
	}
	sum1, sum2 := 0, 0
	for _, x := range nums1 {
		sum1 += x
	}
	for _, x := range nums2 {
		sum2 += x
	}
	if sum1 > sum2 {
		nums1, nums2 = nums2, nums1
		sum1, sum2 = sum2, sum1
	}
	diff := sum2 - sum1
	if diff == 0 {
		return 0
	}
	var contrib [6]int
	for _, x := range nums1 {
		contrib[6-x]++
	}
	for _, x := range nums2 {
		contrib[x-1]++
	}
	ops := 0
	for c := 5; c >= 1 && diff > 0; c-- {
		take := contrib[c]
		need := (diff + c - 1) / c
		if take > need {
			take = need
		}
		ops += take
		diff -= take * c
	}
	if diff > 0 {
		return -1
	}
	return ops
}
