func calculate(s string) int {
	var stack []int
	res, sign := 0, 1
	for i := 0; i < len(s); i++ {
		c := s[i]
		if c >= ''0'' && c <= ''9'' {
			num := 0
			for i < len(s) && s[i] >= ''0'' && s[i] <= ''9'' {
				num = num*10 + int(s[i]-''0'')
				i++
			}
			i--
			res += sign * num
		} else if c == ''+'' {
			sign = 1
		} else if c == ''-'' {
			sign = -1
		} else if c == ''('' {
			stack = append(stack, res, sign)
			res, sign = 0, 1
		} else if c == '')'' {
			prevSign := stack[len(stack)-1]
			prevRes := stack[len(stack)-2]
			stack = stack[:len(stack)-2]
			res = prevRes + prevSign*res
		}
	}
	return res
}
