  ('prep-stacks-queues-calculate-postfix', 'go', 'solution.go', 'package main
func applyOp(a, b int, op string) int {
	switch op {
	case "+":
		return a + b
	case "-":
		return a - b
	case "*":
		return a * b
	case "/":
		return a / b
	}
	return 0
}

func calculatePostfix(tokens []string) int {
	var stack []int
	for _, tok := range tokens {
		switch tok {
		case "+", "-", "*", "/":
			b := stack[len(stack)-1]
			a := stack[len(stack)-2]
			stack = stack[:len(stack)-2]
			stack = append(stack, applyOp(a, b, tok))
		default:
			v := 0
			for i := 0; i < len(tok); i++ {
				v = v*10 + int(tok[i]-''0'')
			}
			stack = append(stack, v)
		}
	}
	return stack[0]
}
