type MovingAverage struct {
	winSize int
	sum     float64
	dq      []int
}

func NewMovingAverage(size int) *MovingAverage {
	return &MovingAverage{winSize: size}
}

func (m *MovingAverage) Next(val int) float64 {
	m.dq = append(m.dq, val)
	m.sum += float64(val)
	if len(m.dq) > m.winSize {
		m.sum -= float64(m.dq[0])
		m.dq = m.dq[1:]
	}
	return m.sum / float64(len(m.dq))
}

func findMovingAverageInSliding(size int) *MovingAverage {
	return NewMovingAverage(size)
}
