	if len(q.maxDQ) > 0 && q.maxDQ[0] == v {
		q.maxDQ = q.maxDQ[1:]
	}
	return v
}

func (q *QueueWithMax) Max() int {
	if len(q.maxDQ) == 0 {
		return 0
	}
	return q.maxDQ[0]
}

