	min  int
	next *minStackNode
}

type MinStack struct {
	top *minStackNode
}

func (s *MinStack) Push(val int) {
	m := val
	if s.top != nil && s.top.min < m {
		m = s.top.min
	}
	s.top = &minStackNode{val: val, min: m, next: s.top}
}

func (s *MinStack) Pop() int {
	if s.top == nil {
		return 0
	}
	v := s.top.val
	s.top = s.top.next
	return v
}

func (s *MinStack) Min() int {
	if s.top == nil {
		return 0
	}
	return s.top.min
}

