		ch := s[i]
		if ch == ''('' || ch == '')'' {
			if !prevSpace {
				out.WriteByte('' '')
			}
			out.WriteByte(ch)
			out.WriteByte('' '')
			prevSpace = true
		} else if ch == '' '' {
			if !prevSpace {
				out.WriteByte('' '')
			}
			prevSpace = true
		} else {
			out.WriteByte(ch)
			prevSpace = false
		}
	}
