	"path/filepath"
)


func cleanDirectoriesRecursively(root string) error {
	entries, err := os.ReadDir(root)
	if err != nil {
		return err
	}
	for _, e := range entries {
		if e.IsDir() {
			sub := filepath.Join(root, e.Name())
			if err := cleanDirectoriesRecursively(sub); err != nil {
				return err
			}
		}
	}
	remaining, err := os.ReadDir(root)
	if err != nil {
		return err
	}
	if len(remaining) == 0 {
		return os.Remove(root)
	}
	return nil
}
