import (
	"os"
	"path/filepath"
)


func findFilesSizeLargerThan5m(root string) ([]string, error) {
	const limit = 5 * 1024 * 1024
	var matches []string
	err := filepath.Walk(root, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if info.IsDir() {
			return nil
		}
		if info.Size() > limit {
			matches = append(matches, path)
		}
		return nil
	})
	return matches, err
}
