  ('prep-streams-io-find-median-in-stream', 'go', 'solution.go', 'package main
type medianHeaps struct {
	low  []int
	high []int
}

func (m *medianHeaps) pushLow(v int) {
	m.low = append(m.low, v)
	i := len(m.low) - 1
	for i > 0 {
		p := (i - 1) / 2
		if m.low[p] >= m.low[i] {
			break
		}
		m.low[p], m.low[i] = m.low[i], m.low[p]
		i = p
	}
}

func (m *medianHeaps) popLow() int {
	top := m.low[0]
	last := m.low[len(m.low)-1]
	m.low = m.low[:len(m.low)-1]
	if len(m.low) == 0 {
		return top
	}
	m.low[0] = last
	i := 0
	for {
		l, r := 2*i+1, 2*i+2
		largest := i
		if l < len(m.low) && m.low[l] > m.low[largest] {
			largest = l
		}
		if r < len(m.low) && m.low[r] > m.low[largest] {
			largest = r
		}
		if largest == i {
			break
		}
		m.low[i], m.low[largest] = m.low[largest], m.low[i]
		i = largest
	}
	return top
}

func (m *medianHeaps) pushHigh(v int) {
	m.high = append(m.high, v)
	i := len(m.high) - 1
	for i > 0 {
		p := (i - 1) / 2
		if m.high[p] <= m.high[i] {
			break
		}
		m.high[p], m.high[i] = m.high[i], m.high[p]
		i = p
	}
}

func (m *medianHeaps) peekLow() int  { return m.low[0] }
func (m *medianHeaps) peekHigh() int { return m.high[0] }

func findMedianInStream() func(int) float64 {
	m := &medianHeaps{}
	return func(v int) float64 {
		m.pushLow(v)
		m.pushHigh(m.popLow())
		if len(m.low) < len(m.high) {
			m.pushLow(m.high[0])
			last := m.high[len(m.high)-1]
			m.high = m.high[:len(m.high)-1]
			if len(m.high) > 0 {
				m.high[0] = last
			}
		}
		if len(m.low) > len(m.high) {
			return float64(m.peekLow())
		}
		return float64(m.peekLow()+m.peekHigh()) / 2
	}
}
