  ('prep-streams-io-rate-limiter-iterator', 'go', 'solution.go', 'package main
import (
	"time"
)


type rateLimiterIterator struct {
	source   []int
	index    int
	rate     float64
	burst    float64
	tokens   float64
	lastTime time.Time
}

func newRateLimiterIterator(source []int, ratePerSec float64, burst float64) *rateLimiterIterator {
	return &rateLimiterIterator{
		source:   source,
		rate:     ratePerSec,
		burst:    burst,
		tokens:   burst,
		lastTime: time.Now(),
	}
}

func (it *rateLimiterIterator) refill() {
	now := time.Now()
	elapsed := now.Sub(it.lastTime).Seconds()
	it.tokens = min(it.burst, it.tokens+elapsed*it.rate)
	it.lastTime = now
}

func (it *rateLimiterIterator) hasNext() bool {
	return it.index < len(it.source)
}

func (it *rateLimiterIterator) next() (int, bool) {
	if !it.hasNext() {
		return 0, false
	}
	for {
		it.refill()
		if it.tokens >= 1 {
			it.tokens--
			val := it.source[it.index]
			it.index++
			return val, true
		}
		time.Sleep(time.Millisecond * 10)
	}
}
