  ('prep-strings-count-words-obtained-after-adding-a-letter', 'go', 'solution.go', 'package main
func wordCount(startWords []string, targetWords []string) int {
	toBitmask := func(w string) int {
		mask := 0
		for _, c := range w {
			mask |= 1 << (c - ''a'')
		}
		return mask
	}
	set := map[int]bool{}
	for _, w := range startWords {
		set[toBitmask(w)] = true
	}
	cnt := 0
	for _, w := range targetWords {
		mask := toBitmask(w)
		for _, c := range w {
			if set[mask^(1<<(c-''a''))] {
				cnt++
				break
			}
		}
	}
	return cnt
}
