import "strings"


func findReplaceString(s string, indices []int, sources []string, targets []string) string {
	type op struct{ src, tgt string }
	m := map[int]op{}
	for i, idx := range indices {
		m[idx] = op{sources[i], targets[i]}
	}
	var sb strings.Builder
	i := 0
	for i < len(s) {
		if o, ok := m[i]; ok && i+len(o.src) <= len(s) && s[i:i+len(o.src)] == o.src {
			sb.WriteString(o.tgt)
			i += len(o.src)
		} else {
			sb.WriteByte(s[i])
			i++
		}
	}
	return sb.String()
}
