import "sort"


func longestDiverseString(a int, b int, c int) string {
	type pair struct {
		cnt int
		ch  byte
	}
	var res []byte
	counts := []pair{{a, ''a''}, {b, ''b''}, {c, ''c''}}
	for {
		sort.Slice(counts, func(i, j int) bool { return counts[i].cnt > counts[j].cnt })
		pick := -1
		for i := range counts {
			if counts[i].cnt == 0 {
				continue
			}
			n := len(res)
			if n >= 2 && res[n-1] == counts[i].ch && res[n-2] == counts[i].ch {
				continue
			}
			pick = i
			break
		}
		if pick == -1 {
			break
		}
		res = append(res, counts[pick].ch)
		counts[pick].cnt--
	}
	return string(res)
}
