  ('prep-strings-min-window-substring', 'go', 'solution.go', 'package main
func minWindowSubstring(s, t string) string {
	if len(t) == 0 {
		return ""
	}
	need := map[byte]int{}
	for i := 0; i < len(t); i++ {
		need[t[i]]++
	}
	required := len(need)
	formed := 0
	have := map[byte]int{}
	l, bestL, bestLen := 0, 0, int(^uint(0)>>1)
	for r := 0; r < len(s); r++ {
		c := s[r]
		have[c]++
		if cnt, ok := need[c]; ok && have[c] == cnt {
			formed++
		}
		for formed == required && l <= r {
			if r-l+1 < bestLen {
				bestLen = r - l + 1
				bestL = l
			}
			left := s[l]
			have[left]--
			if cnt, ok := need[left]; ok && have[left] < cnt {
				formed--
			}
			l++
		}
	}
	if bestLen == int(^uint(0)>>1) {
		return ""
	}
	return s[bestL : bestL+bestLen]
}
