func minRemoveToMakeValid(s string) string {
	buf := []byte(s)
	var stack []int
	for i := 0; i < len(buf); i++ {
		if buf[i] == ''('' {
			stack = append(stack, i)
		} else if buf[i] == '')'' {
			if len(stack) > 0 {
				stack = stack[:len(stack)-1]
			} else {
				buf[i] = ''*''
			}
		}
	}
	for _, idx := range stack {
		buf[idx] = ''*''
	}
	res := make([]byte, 0, len(buf))
	for _, b := range buf {
		if b != ''*'' {
			res = append(res, b)
		}
	}
	return string(res)
}
