func findMinDifference(timePoints []string) int {
	mins := make([]int, len(timePoints))
	for i, tp := range timePoints {
		mins[i] = int(tp[0]-''0'')*600 + int(tp[1]-''0'')*60 + int(tp[3]-''0'')*10 + int(tp[4]-''0'')
	}
	sort.Ints(mins)
	res := 1440 - mins[len(mins)-1] + mins[0]
	for i := 1; i < len(mins); i++ {
		if d := mins[i] - mins[i-1]; d < res {
			res = d
		}
	}
	return res
}
