func reverseWords(s string) string {
	b := []byte(s)
	trim := func() {
		start, end := 0, len(b)-1
		for start <= end && b[start] == '' '' {
			start++
		}
		for end >= start && b[end] == '' '' {
			end--
		}
		b = b[start : end+1]
	}
	trim()
	rev := func(l, r int) {
		for l < r {
			b[l], b[r] = b[r], b[l]
			l++
			r--
		}
	}
	rev(0, len(b)-1)
	i := 0
	for i < len(b) {
		j := i
		for j < len(b) && b[j] != '' '' {
			j++
		}
		rev(i, j-1)
		i = j + 1
	}
	return string(b)
}
