func sumPrefixScores(words []string) []int {
	type node struct {
		ch    [26]*node
		count int
	}
	root := &node{}
	for _, w := range words {
		cur := root
		for i := 0; i < len(w); i++ {
			c := w[i] - ''a''
			if cur.ch[c] == nil {
				cur.ch[c] = &node{}
			}
			cur = cur.ch[c]
			cur.count++
		}
	}
	res := make([]int, len(words))
	for i, w := range words {
		cur := root
		for j := 0; j < len(w); j++ {
			cur = cur.ch[w[j]-''a'']
			res[i] += cur.count
		}
	}
	return res
}
