func canTransform(start string, target string) bool {
	n := len(start)
	i, j := 0, 0
	for i < n || j < n {
		for i < n && start[i] == ''X'' {
			i++
		}
		for j < n && target[j] == ''X'' {
			j++
		}
		if (i == n) != (j == n) {
			return false
		}
		if i == n {
			break
		}
		if start[i] != target[j] {
			return false
		}
		if start[i] == ''L'' && i < j {
			return false
		}
		if start[i] == ''R'' && i > j {
			return false
		}
		i++
		j++
	}
	return true
}
