  ('prep-strings-text-justification', 'go', 'solution.go', 'package main
import "strings"


func fullJustify(words []string, maxWidth int) []string {
	var res []string
	i := 0
	for i < len(words) {
		lineLen := len(words[i])
		j := i + 1
		for j < len(words) && lineLen+1+len(words[j]) <= maxWidth {
			lineLen += 1 + len(words[j])
			j++
		}
		numWords := j - i
		var sb strings.Builder
		if j == len(words) || numWords == 1 {
			sb.WriteString(words[i])
			for k := i + 1; k < j; k++ {
				sb.WriteByte('' '')
				sb.WriteString(words[k])
			}
			for sb.Len() < maxWidth {
				sb.WriteByte('' '')
			}
		} else {
			totalSpaces := maxWidth - (lineLen - (numWords - 1))
			perGap := totalSpaces / (numWords - 1)
			extra := totalSpaces % (numWords - 1)
			for k := i; k < j; k++ {
				sb.WriteString(words[k])
				if k < j-1 {
					gaps := perGap
					if k-i < extra {
						gaps++
					}
					for g := 0; g < gaps; g++ {
						sb.WriteByte('' '')
					}
				}
			}
		}
		res = append(res, sb.String())
		i = j
	}
	return res
}
