  ('prep-strings-word-wrap', 'go', 'solution.go', 'package main
func wordWrap(words []string, maxWidth int) []string {
	n := len(words)
	if n == 0 {
		return nil
	}
	dp := make([]int, n+1)
	next := make([]int, n)
	for i := n - 1; i >= 0; i-- {
		dp[i] = int(^uint(0) >> 1)
		length := 0
		for j := i; j < n; j++ {
			if j > i {
				length++
			}
			length += len(words[j])
			if length > maxWidth {
				break
			}
			cost := 0
			if j < n-1 {
				rem := maxWidth - length
				cost = rem*rem + dp[j+1]
			}
			if cost < dp[i] {
				dp[i] = cost
				next[i] = j + 1
			}
		}
	}
	out := []string{}
	i := 0
	for i < n {
		j := next[i] - 1
		line := joinWords(words[i : j+1])
		out = append(out, line)
		i = next[i]
	}
	return out
}

func joinWords(words []string) string {
	if len(words) == 0 {
		return ""
	}
	out := words[0]
	for i := 1; i < len(words); i++ {
		out += " " + words[i]
	}
	return out
}
