func maxPathSum(root *TreeNode) int {
	res := -1 << 31
	var dfs func(node *TreeNode) int
	dfs = func(node *TreeNode) int {
		if node == nil {
			return 0
		}
		left := dfs(node.Left)
		right := dfs(node.Right)
		if left < 0 {
			left = 0
		}
		if right < 0 {
			right = 0
		}
		if node.Val+left+right > res {
			res = node.Val + left + right
		}
		if left > right {
			return node.Val + left
		}
		return node.Val + right
	}
	dfs(root)
	return res
}
