func treeToDoublyList(root *TreeNode) *TreeNode {
	if root == nil {
		return nil
	}
	var first, last *TreeNode
	var inorder func(node *TreeNode)
	inorder = func(node *TreeNode) {
		if node == nil {
			return
		}
		inorder(node.Left)
		if last != nil {
			last.Right = node
			node.Left = last
		} else {
			first = node
		}
		last = node
		inorder(node.Right)
	}
	inorder(root)
	first.Left = last
	last.Right = first
	return first
}
