	Val         int
	Left, Right *TreeNode
}

type ListNode struct {
	Val  int
	Next *ListNode
}

func convertSortedLinkedListToBst(head *ListNode) *TreeNode {
	n := 0
	for cur := head; cur != nil; cur = cur.Next {
		n++
	}
	cur := head
	var build func(l, r int) *TreeNode
	build = func(l, r int) *TreeNode {
		if l > r {
			return nil
		}
		m := (l + r) / 2
		left := build(l, m-1)
		node := &TreeNode{Val: cur.Val}
		cur = cur.Next
		node.Left = left
		node.Right = build(m+1, r)
		return node
	}
	return build(0, n-1)
}
