		if node == nil {
			return true
		}
		if lo != nil && node.Val <= lo.Val {
			return false
		}
		if hi != nil && node.Val >= hi.Val {
			return false
		}
		return valid(node.Left, lo, node) && valid(node.Right, node, hi)
	}
	return valid(root, nil, nil)
