		return true
	}
	return isSubtree(root.Left, sub) || isSubtree(root.Right, sub)
}

func sameTree(a, b *TreeNode) bool {
	if a == nil && b == nil {
		return true
	}
	if a == nil || b == nil || a.Val != b.Val {
		return false
	}
	return sameTree(a.Left, b.Left) && sameTree(a.Right, b.Right)
}
