func longestPath(parent []int, s string) int {
	n := len(parent)
	adj := make([][]int, n)
	for i := 1; i < n; i++ {
		adj[parent[i]] = append(adj[parent[i]], i)
	}
	res := 0
	var dfs func(node int) int
	dfs = func(node int) int {
		max1, max2 := 0, 0
		for _, child := range adj[node] {
			childLen := dfs(child)
			if s[child] != s[node] {
				if childLen > max1 {
					max2 = max1
					max1 = childLen
				} else if childLen > max2 {
					max2 = childLen
				}
			}
		}
		if max1+max2+1 > res {
			res = max1 + max2 + 1
		}
		return max1 + 1
	}
	dfs(0)
	return res
}
