  ('prep-trees-nary-tree-monarchy-succession', 'go', 'solution.go', 'package main
type Member struct {
	Name       string
	Successors []*Member
}

type Monarchy struct {
	members map[string]*Member
	king    *Member
}

func buildMonarchyMap(lines []string) *Monarchy {
	m := &Monarchy{members: make(map[string]*Member)}
	for _, line := range lines {
		parts := splitFields(line)
		if len(parts) < 2 {
			continue
		}
		parentName := parts[0]
		if m.members[parentName] == nil {
			m.members[parentName] = &Member{Name: parentName}
		}
		if parentName == "monarch" || m.king == nil {
			m.king = m.members[parentName]
		}
		for i := 1; i < len(parts); i++ {
			childName := parts[i]
			if m.members[childName] == nil {
				m.members[childName] = &Member{Name: childName}
			}
			m.members[parentName].Successors = append(m.members[parentName].Successors, m.members[childName])
		}
	}
	return m
}

func splitFields(s string) []string {
	out := make([]string, 0)
	cur := ""
	for _, ch := range s {
		if ch == '' '' || ch == ''\t'' {
			if cur != "" {
				out = append(out, cur)
				cur = ""
			}
		} else {
			cur += string(ch)
		}
	}
	if cur != "" {
		out = append(out, cur)
	}
	return out
}

func buildMonarchyTree(root *Member) {
	for _, succ := range root.Successors {
		buildMonarchyTree(succ)
	}
}

func monarchySuccessionOrder(lines []string) []string {
	m := buildMonarchyMap(lines)
	if m.king == nil {
		return nil
	}
	buildMonarchyTree(m.king)
	return preorderSuccessors(m.king)
}

func preorderSuccessors(root *Member) []string {
	if root == nil {
		return nil
	}
	res := make([]string, 0)
	stack := []*Member{root}
	for len(stack) > 0 {
		curr := stack[len(stack)-1]
		stack = stack[:len(stack)-1]
		res = append(res, curr.Name)
		for i := len(curr.Successors) - 1; i >= 0; i-- {
			stack = append(stack, curr.Successors[i])
		}
	}
	return res
}
