type TreeNode struct {
	Val         int
	Left, Right *TreeNode
}

func printVertical(root *TreeNode) [][]int {
	if root == nil {
		return nil
	}
	type pair struct {
		node *TreeNode
		col  int
	}
	cols := map[int][]int{}
	minC, maxC := 0, 0
	q := []pair{{root, 0}}
	for len(q) > 0 {
		p := q[0]
		q = q[1:]
		cols[p.col] = append(cols[p.col], p.node.Val)
		if p.col < minC {
			minC = p.col
		}
		if p.col > maxC {
			maxC = p.col
		}
		if p.node.Left != nil {
			q = append(q, pair{p.node.Left, p.col - 1})
		}
		if p.node.Right != nil {
			q = append(q, pair{p.node.Right, p.col + 1})
		}
	}
	out := [][]int{}
	for c := minC; c <= maxC; c++ {
		if v, ok := cols[c]; ok {
			out = append(out, v)
		}
	}
	return out
}
