  ('prep-trees-serialize-and-deserialize', 'go', 'solution.go', 'package main
type TreeNode struct {
	Val         int
	Left, Right *TreeNode
}

func serializeAndDeserialize(root *TreeNode) (string, *TreeNode) {
	if root == nil {
		return "", nil
	}
	var parts []string
	q := []*TreeNode{root}
	for len(q) > 0 {
		node := q[0]
		q = q[1:]
		if node == nil {
			parts = append(parts, "#")
			continue
		}
		parts = append(parts, itoa(node.Val))
		q = append(q, node.Left, node.Right)
	}
	data := joinComma(parts)
	return data, deserializeTree(data)
}

func itoa(n int) string {
	if n == 0 {
		return "0"
	}
	neg := false
	if n < 0 {
		neg = true
		n = -n
	}
	var d []byte
	for n > 0 {
		d = append(d, byte(''0''+n%10))
		n /= 10
	}
	if neg {
		d = append(d, ''-'')
	}
	for i, j := 0, len(d)-1; i < j; i, j = i+1, j-1 {
		d[i], d[j] = d[j], d[i]
	}
	return string(d)
}

func joinComma(parts []string) string {
	if len(parts) == 0 {
		return ""
	}
	out := parts[0]
	for i := 1; i < len(parts); i++ {
		out += "," + parts[i]
	}
	return out
}

func splitComma(s string) []string {
	out := []string{}
	start := 0
	for i := 0; i <= len(s); i++ {
		if i == len(s) || s[i] == '','' {
			out = append(out, s[start:i])
			start = i + 1
		}
	}
	return out
}

func atoi(s string) int {
	if s == "#" || s == "" {
		return 0
	}
	neg := false
	i := 0
	if s[0] == ''-'' {
		neg = true
		i = 1
	}
	n := 0
	for ; i < len(s); i++ {
		n = n*10 + int(s[i]-''0'')
	}
	if neg {
		return -n
	}
	return n
}

func deserializeTree(data string) *TreeNode {
	if data == "" {
		return nil
	}
	vals := splitComma(data)
	idx := 0
	var build func() *TreeNode
	build = func() *TreeNode {
		if idx >= len(vals) || vals[idx] == "#" {
			idx++
			return nil
		}
		node := &TreeNode{Val: atoi(vals[idx])}
		idx++
		node.Left = build()
		node.Right = build()
		return node
	}
	return build()
}
