import "sort"


type TreeNode struct {
	Val   int
	Left  *TreeNode
	Right *TreeNode
}

type pt struct{ row, val int }

func verticalTraversal(root *TreeNode) [][]int {
	if root == nil {
		return nil
	}
	cols := map[int][]pt{}
	minC, maxC := 0, 0
	type item struct {
		node *TreeNode
		r, c int
	}
	q := []item{{root, 0, 0}}
	for len(q) > 0 {
		cur := q[0]
		q = q[1:]
		cols[cur.c] = append(cols[cur.c], pt{cur.r, cur.node.Val})
		if cur.c < minC {
			minC = cur.c
		}
		if cur.c > maxC {
			maxC = cur.c
		}
		if cur.node.Left != nil {
			q = append(q, item{cur.node.Left, cur.r + 1, cur.c - 1})
		}
		if cur.node.Right != nil {
			q = append(q, item{cur.node.Right, cur.r + 1, cur.c + 1})
		}
	}
	var res [][]int
	for c := minC; c <= maxC; c++ {
		pts := cols[c]
		sort.Slice(pts, func(i, j int) bool {
			if pts[i].row == pts[j].row {
				return pts[i].val < pts[j].val
			}
			return pts[i].row < pts[j].row
		})
		vals := make([]int, len(pts))
		for i, p := range pts {
			vals[i] = p.val
		}
		res = append(res, vals)
	}
	return res
}
