  ('prep-tries-find-distinct-palindromic-sub', 'go', 'solution.go', 'package main
type SuffixTrieNode struct {
	children map[rune]*SuffixTrieNode
}

func newSuffixTrieNode() *SuffixTrieNode {
	return &SuffixTrieNode{children: make(map[rune]*SuffixTrieNode)}
}

func buildSuffixTrie(s string) *SuffixTrieNode {
	root := newSuffixTrieNode()
	for i := 0; i < len(s); i++ {
		node := root
		for j := i; j < len(s); j++ {
			ch := rune(s[j])
			if node.children[ch] == nil {
				node.children[ch] = newSuffixTrieNode()
			}
			node = node.children[ch]
		}
	}
	return root
}

func isPalindrome(s string) bool {
	for i, j := 0, len(s)-1; i < j; i, j = i+1, j-1 {
		if s[i] != s[j] {
			return false
		}
	}
	return true
}

func findPaliSub(node *SuffixTrieNode, s string, seen map[string]bool) int {
	if node == nil {
		return 0
	}
	count := 0
	if isPalindrome(s) && s != "" && !seen[s] {
		seen[s] = true
		count++
	}
	for ch, child := range node.children {
		count += findPaliSub(child, s+string(ch), seen)
	}
	return count
}

func findDistinctPalindromicSub(s string) int {
	root := buildSuffixTrie(s)
	return findPaliSub(root, "", make(map[string]bool))
}
