  ('prep-tries-longest-repeated-substring', 'go', 'solution.go', 'package main
import (
	"sort"
)


func lcp(a, b string) string {
	n := len(a)
	if len(b) < n {
		n = len(b)
	}
	for i := 0; i < n; i++ {
		if a[i] != b[i] {
			return a[:i]
		}
	}
	return a[:n]
}

func longestRepeatedSubstring(str string) string {
	n := len(str)
	if n == 0 {
		return ""
	}
	suffixes := make([]string, n)
	for i := 0; i < n; i++ {
		suffixes[i] = str[i:]
	}
	sort.Strings(suffixes)
	longest := ""
	for i := 1; i < n; i++ {
		common := lcp(suffixes[i-1], suffixes[i])
		if len(common) > len(longest) {
			longest = common
		}
	}
	return longest
}
