import (
	"fmt"
	"sync"
)

// producer sends n values then closes; direction type enforces send-only.
func producer(out chan<- int, n int) {
	for i := 0; i < n; i++ {
		out <- i
	}
	close(out)
}

// merge fans in two receive-only channels using comma-ok to detect close.
func merge(a, b <-chan int) <-chan int {
	out := make(chan int)
	var wg sync.WaitGroup
	drain := func(c <-chan int) {
		defer wg.Done()
		for {
			v, ok := <-c
			if !ok {
				return // closed channel: ok is false, v is zero value
			}
			out <- v
		}
	}
	wg.Add(2)
	go drain(a)
	go drain(b)
	go func() {
		wg.Wait()
		close(out)
	}()
	return out
}

func main() {
	a := make(chan int)    // unbuffered: send blocks until received
	b := make(chan int, 3) // buffered: send blocks only when full
	go producer(a, 3)
	go producer(b, 3)

	sum := 0
	for v := range merge(a, b) { // range stops when out is closed
		sum += v
	}
	fmt.Println(sum)
