// worker blocks until it gets a result or the context is cancelled.
func worker(ctx context.Context, d time.Duration) error {
	select {
	case <-time.After(d):
		return nil
	case <-ctx.Done():
		return ctx.Err()
	}
}

func main() {
	parent, cancel := context.WithCancel(context.Background())
	defer cancel()

	child, childCancel := context.WithTimeout(parent, 50*time.Millisecond)
	defer childCancel()

	// Slower than the child deadline: expect DeadlineExceeded.
	if err := worker(child, 200*time.Millisecond); err != nil {
		fmt.Println("child:", err, errors.Is(err, context.DeadlineExceeded))
	}

	// Cancelling the parent propagates to any further derived contexts.
	gc, gcCancel := context.WithCancel(parent)
	defer gcCancel()
	cancel()
	if err := worker(gc, time.Hour); err != nil {
		fmt.Println("grandchild:", err, errors.Is(err, context.Canceled))
	}
}
