import "fmt"

type Point struct {
	X, Y int
}

// newPoint returns a pointer; the value must outlive the frame, so it escapes.
func newPoint(x, y int) *Point {
	p := Point{X: x, Y: y}
	return &p
}

// sumLocal keeps everything on the stack: no pointer leaves the frame.
func sumLocal(n int) int {
	acc := Point{}
	for i := 0; i < n; i++ {
		acc.X += i
		acc.Y -= i
	}
	return acc.X + acc.Y
}

// leak forces a heap allocation by storing the value behind an interface.
func leak(v int) fmt.Stringer {
	return myInt(v)
}

type myInt int

func (m myInt) String() string {
	return fmt.Sprintf("myInt(%d)", int(m))
}

func main() {
	p := newPoint(3, 4)
	fmt.Println(p.X+p.Y, sumLocal(10), leak(7))
}
