import (
	"fmt"
	"runtime"
	"runtime/debug"
)

func main() {
	// GOGC=100 means: trigger the next GC when the live heap has grown
	// by 100% since the last mark-termination. Return value is the prior.
	prev := debug.SetGCPercent(100)
	fmt.Println("previous GOGC:", prev)

	// GOMEMLIMIT is a soft memory ceiling. The pacer runs GC more
	// aggressively as usage approaches it; -1 leaves it unchanged.
	oldLimit := debug.SetMemoryLimit(-1)
	fmt.Println("current soft limit bytes:", oldLimit)

	var before, after runtime.MemStats
	runtime.ReadMemStats(&before)

	retained := make([][]byte, 0, 1024)
	for i := 0; i < 1024; i++ {
		retained = append(retained, make([]byte, 4096))
		_ = make([]byte, 4096) // immediately unreachable garbage
	}

	runtime.GC() // blocking cycle: mark then sweep
	runtime.ReadMemStats(&after)

	fmt.Println("completed GC cycles:", after.NumGC-before.NumGC)
	fmt.Println("retained slices:", len(retained))
	fmt.Printf("heap goal bytes: %d\n", after.NextGC)
	runtime.KeepAlive(retained)
}
