import (
	"bufio"
	"bytes"
	"crypto/sha256"
	"fmt"
	"io"
	"strings"
)

// countingReader wraps an io.Reader and tracks how many bytes flowed through it.
type countingReader struct {
	r io.Reader
	n int64
}

func (c *countingReader) Read(p []byte) (int, error) {
	n, err := c.r.Read(p)
	c.n += int64(n)
	return n, err
}

func main() {
	src := strings.NewReader("the quick brown fox\njumps over the lazy dog\n")

	// Count bytes as they are read.
	cr := &countingReader{r: src}

	// Tee everything read into a hash so we digest while we stream.
	h := sha256.New()
	tee := io.TeeReader(cr, h)

	// Fan out the output to two sinks at once.
	var buf bytes.Buffer
	mirror := &bytes.Buffer{}
	dst := io.MultiWriter(&buf, mirror)

	if _, err := io.Copy(dst, tee); err != nil {
		panic(err)
	}

	// Line-oriented reads over the captured bytes.
	sc := bufio.NewScanner(&buf)
	lines := 0
	for sc.Scan() {
		lines++
	}
	if err := sc.Err(); err != nil {
		panic(err)
	}

	fmt.Printf("bytes=%d lines=%d sum=%x\n", cr.n, lines, h.Sum(nil)[:4])
}
