import (
	"errors"
	"fmt"
)

type resource struct {
	name string
}

func (r *resource) Close() error {
	if r.name == "bad" {
		return fmt.Errorf("close %s: flush failed", r.name)
	}
	fmt.Println("closed", r.name)
	return nil
}

func open(name string) (*resource, error) {
	if name == "" {
		return nil, errors.New("empty name")
	}
	return &resource{name: name}, nil
}

// process opens two resources and guarantees cleanup even on partial failure.
// The named return err is rewritten by the deferred close so a flush error is
// not silently swallowed.
func process(a, b string) (err error) {
	ra, err := open(a)
	if err != nil {
		return err
	}
	defer func() {
		if cerr := ra.Close(); cerr != nil && err == nil {
			err = cerr
		}
	}()

	rb, err := open(b)
	if err != nil {
		return err
	}
	defer func() {
		if cerr := rb.Close(); cerr != nil && err == nil {
			err = cerr
		}
	}()

	fmt.Println("processing", ra.name, rb.name)
	return nil
}

func main() {
	names := []string{"ok", "bad"}
	for _, n := range names {
		if err := process("main", n); err != nil {
			fmt.Println("error:", err)
		}
	}
}
