// sink defeats dead-code elimination: a package-level variable
// the compiler cannot prove is unused.
var sink string

func buildWithBuilder(parts []string) string {
	var b strings.Builder
	for _, p := range parts {
		b.WriteString(p)
	}
	return b.String()
}

func benchmarkBuilder(b *testing.B) {
	parts := make([]string, 128)
	for i := range parts {
		parts[i] = "chunk"
	}
	b.ReportAllocs()
	b.ResetTimer() // exclude the setup above from timing
	var local string
	for i := 0; i < b.N; i++ {
		local = buildWithBuilder(parts)
	}
	sink = local // publish so the loop body is not eliminated
}

func main() {
	res := testing.Benchmark(benchmarkBuilder)
	fmt.Printf("%d ns/op, %d B/op, %d allocs/op\n",
		res.NsPerOp(), res.AllocedBytesPerOp(), res.AllocsPerOp())
}
