  ('go-perf-allocations', 'go', 'main.go', 'package main

import (
	"fmt"
	"strings"
)

// joinNaive builds the result with repeated string concatenation, forcing a
// fresh heap allocation and full copy on every iteration: O(n^2) bytes copied.
func joinNaive(parts []string) string {
	var s string
	for _, p := range parts {
		s += p
	}
	return s
}

// joinFast preallocates the exact byte capacity, then writes into a
// strings.Builder whose backing array never has to grow.
func joinFast(parts []string) string {
	total := 0
	for _, p := range parts {
		total += len(p)
	}
	var b strings.Builder
	b.Grow(total)
	for _, p := range parts {
		b.WriteString(p)
	}
	return b.String()
}

// sumBCE hoists the length so the compiler can prove i is always in range and
// eliminate the per-iteration bounds check on xs[i].
func sumBCE(xs []int) int {
	sum := 0
	for i := 0; i < len(xs); i++ {
		sum += xs[i]
	}
	return sum
}

func main() {
	parts := []string{"algo", "-", "moves", "!"}
	fmt.Println(joinNaive(parts) == joinFast(parts))
	fmt.Println(sumBCE([]int{1, 2, 3, 4}))
}
