// roundTrip encodes m to JSON and decodes it back; it is the property under test.
func roundTrip(m map[string]int) (map[string]int, error) {
	b, err := json.Marshal(m)
	if err != nil {
		return nil, err
	}
	out := map[string]int{}
	if err := json.Unmarshal(b, &out); err != nil {
		return nil, err
	}
	return out, nil
}

// FuzzRoundTrip checks the invariant: decode(encode(x)) == x for a single-key map.
func FuzzRoundTrip(f *testing.F) {
	f.Add("key", 0)
	f.Add("", -1)
	f.Add("é", 42)
	f.Fuzz(func(t *testing.T, k string, v int) {
		in := map[string]int{k: v}
		out, err := roundTrip(in)
		if err != nil {
			t.Skip() // encoding of some inputs is out of scope
		}
		if got := out[k]; got != v {
			t.Fatalf("round-trip mismatch: key=%q want %d got %d", k, v, got)
		}
	})
}

func main() {
	out, _ := roundTrip(map[string]int{"answer": 42})
	fmt.Println(out)
