import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"net/http/httptest"
)

// Seam: consumer defines the small interface it needs.
type RateFetcher interface {
	Rate(ctx context.Context, ccy string) (float64, error)
}

type httpFetcher struct {
	client *http.Client
	base   string
}

func (f httpFetcher) Rate(ctx context.Context, ccy string) (float64, error) {
	req, _ := http.NewRequestWithContext(ctx, http.MethodGet, f.base+"/rate/"+ccy, nil)
	resp, err := f.client.Do(req)
	if err != nil {
		return 0, err
	}
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusOK {
		return 0, fmt.Errorf("status %d", resp.StatusCode)
	}
	var out struct{ Rate float64 }
	if err := json.NewDecoder(resp.Body).Decode(&out); err != nil {
		return 0, err
	}
	return out.Rate, nil
}

// Convert takes the interface, not a concrete type: injectable seam.
func Convert(ctx context.Context, f RateFetcher, ccy string, amt float64) (float64, error) {
	r, err := f.Rate(ctx, ccy)
	if err != nil {
		return 0, err
	}
	return amt * r, nil
}

func main() {
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		json.NewEncoder(w).Encode(map[string]float64{"Rate": 1.1})
	}))
	defer srv.Close()

	f := httpFetcher{client: srv.Client(), base: srv.URL}
	total, _ := Convert(context.Background(), f, "EUR", 100)
	fmt.Printf("%.1f\n", total)
}
