  ('go-design-rate-limiter', 'go', 'main.go', 'package main

import (
	"fmt"
	"sync"
	"time"

	"golang.org/x/time/rate"
)

// PerKeyLimiter hands out a token-bucket limiter per client key. Each entry
// records a last-seen time so a background sweeper (not shown) can evict idle
// keys and keep the map from growing unbounded.
type PerKeyLimiter struct {
	mu      sync.Mutex
	buckets map[string]*entry
	r       rate.Limit
	burst   int
	idleFor time.Duration
}

type entry struct {
	lim  *rate.Limiter
	seen time.Time
}

func NewPerKeyLimiter(r rate.Limit, burst int, idleFor time.Duration) *PerKeyLimiter {
	return &PerKeyLimiter{
		buckets: make(map[string]*entry),
		r:       r,
		burst:   burst,
		idleFor: idleFor,
	}
}

func (p *PerKeyLimiter) get(key string) *rate.Limiter {
	p.mu.Lock()
	defer p.mu.Unlock()
	e, ok := p.buckets[key]
	if !ok {
		e = &entry{lim: rate.NewLimiter(p.r, p.burst)}
		p.buckets[key] = e
	}
	e.seen = time.Now()
	return e.lim
}

func (p *PerKeyLimiter) Allow(key string) bool {
	return p.get(key).Allow()
}

func main() {
	// 2 tokens/sec, burst of 3.
	p := NewPerKeyLimiter(rate.Every(500*time.Millisecond), 3, time.Minute)
	allowed := 0
	for i := 0; i < 5; i++ {
		if p.Allow("user-42") {
			allowed++
		}
	}
	fmt.Printf("burst admitted %d of 5\n", allowed)
}
