  ('go-design-lru-cache', 'go', 'main.go', 'package main

import (
	"container/list"
	"fmt"
	"sync"
	"time"
)

type entry[K comparable, V any] struct {
	key     K
	val     V
	expires time.Time
}

// shard is a single-mutex LRU: map for O(1) lookup, list for O(1) reorder.
type shard[K comparable, V any] struct {
	mu    sync.Mutex
	cap   int
	ttl   time.Duration
	ll    *list.List
	items map[K]*list.Element
}

func newShard[K comparable, V any](capacity int, ttl time.Duration) *shard[K, V] {
	return &shard[K, V]{
		cap:   capacity,
		ttl:   ttl,
		ll:    list.New(),
		items: make(map[K]*list.Element, capacity),
	}
}

func (s *shard[K, V]) Get(k K) (V, bool) {
	s.mu.Lock()
	defer s.mu.Unlock()
	el, ok := s.items[k]
	if !ok {
		var zero V
		return zero, false
	}
	e := el.Value.(*entry[K, V])
	if !e.expires.IsZero() && time.Now().After(e.expires) {
		s.removeElem(el)
		var zero V
		return zero, false
	}
	s.ll.MoveToFront(el)
	return e.val, true
}

func (s *shard[K, V]) Put(k K, v V) {
	s.mu.Lock()
	defer s.mu.Unlock()
	if el, ok := s.items[k]; ok {
		e := el.Value.(*entry[K, V])
		e.val, e.expires = v, s.deadline()
		s.ll.MoveToFront(el)
		return
	}
	el := s.ll.PushFront(&entry[K, V]{key: k, val: v, expires: s.deadline()})
	s.items[k] = el
	if s.ll.Len() > s.cap {
		s.removeElem(s.ll.Back())
	}
}

func (s *shard[K, V]) deadline() time.Time {
	if s.ttl <= 0 {
		return time.Time{}
	}
	return time.Now().Add(s.ttl)
}

func (s *shard[K, V]) removeElem(el *list.Element) {
	s.ll.Remove(el)
	delete(s.items, el.Value.(*entry[K, V]).key)
}

func main() {
	s := newShard[string, int](2, 0)
	s.Put("a", 1)
	s.Put("b", 2)
	s.Get("a")    // touch a -> b is now the coldest
	s.Put("c", 3) // evicts b
	_, okB := s.Get("b")
	v, okA := s.Get("a")
	fmt.Println(okB, okA, v)
}
